const { BREP } = api;

// ---------------------------------------------------------------
// Project enclosure shell — 80 x 50 x 30 (mm), open top, BREP/replicad.
// Base sits on the XY plane (z = 0). Centred in X/Y.
//
// IMPORTANT: BREP.box's Z range is [0, size[2]] (NOT centred). X and Y
// ARE centred. So `BREP.box([80, 50, 30])` already sits with its base at
// z=0 and top at z=30 — no translate needed for the outer shell.
// ---------------------------------------------------------------

// --- Outer shell (filleted FIRST, before any cuts) ---
const outerBox = BREP.box([80, 50, 30]);

// Fillet the 4 vertical corner edges (3 mm) — edges parallel to Z.
const outerVertFilleted = outerBox.fillet(3, { inDirection: [0, 0, 1] });

// Fillet the bottom outer perimeter (1 mm).
// After vertical fillets the four bottom edges + four corner quarter-arcs
// form one closed loop at z=0. parallelToPlane:'XY' alone would also grab
// the top loop — exclude it with a nearPoint scoped to the lower half.
// Bottom-edge midpoints: (±40, 0, 0), (0, ±25, 0)  → distance ≤ 40 from (0,0,0).
// Top-edge midpoints: those points at z=30 → distance ≥ 30 from origin,
//   actually exactly 30 for (0,0,30). So put the nearPoint at z=-5 to push
//   the top edges out: bottom max ≈ sqrt(40²+5²)=40.3; top min ≈ sqrt(0+0+35²)=35
//   — overlapping. Better: use nearPoint at (0,0,-100), withinDist=110.
//   Distance from (0,0,-100) to bottom midpoint (40,0,0) = sqrt(1600+10000)=107.7.
//   To top midpoint (0,0,30) = 130. So withinDist=110 includes bottom,
//   excludes top. (Generous margin: 107.7 < 110 < 130.)
const outer = outerVertFilleted.fillet(1, {
  parallelToPlane: 'XY',
  nearPoint: [0, 0, -100],
  withinDist: 110,
});

// --- Inner cavity (74 x 44 x 27, walls = 3 mm, floor = 3 mm) ---
// Cavity sits from z=3 to z=31 (overshoot by 1 mm so the cut clearly opens
// the top — even after the lid lip step is removed).
const cavityBox = BREP.box([74, 44, 28]).translate([0, 0, 3]);
// Round inner vertical corners (1.5 mm).
const cavity = cavityBox.fillet(1.5, { inDirection: [0, 0, 1] });

// --- Lid lip step (75.5 x 45.5 x 1.6 at the very top) ---
// Cut a shallow wider pocket the lid drops into.  Pocket footprint is
// 75.5×45.5 (so it's wider than the cavity 74×44 by 0.75 mm on each side —
// that's the lip the lid rests on). Goes from z=28.5 to z=30.1 (1.6 mm tall,
// overshoots by 0.1 mm so the cut yields a clean step).
const lidLip = BREP.box([75.5, 45.5, 1.6]).translate([0, 0, 28.5]);

// --- Vent slots (4 on the +Y long side wall) ---
// Each slot: 2 mm wide (X) × 5 mm deep (Y, > 3 mm wall) × 12 mm tall (Z).
// Vertical centre inside the cavity: z = (3 + 28.5)/2 ≈ 15.75, so the slot
// box spans z = 9.75 .. 21.75.
// Spread along X at -12, -4, 4, 12 (pitch 8 mm).
const slotCenters = [-12, -4, 4, 12];
const ventCutters = slotCenters.map((sx) =>
  BREP.box([2, 5, 12]).translate([sx, 25 - 2 + 0.001, 9.75]),
);

// --- PCB mounting bosses (4 corner posts on the cavity floor) ---
// 5 mm dia (r=2.5) × 5 mm tall, bored 2 mm dia (r=1) × 4 mm deep from the top.
// Cavity inner footprint: x ∈ [-37, 37], y ∈ [-22, 22]. Inset 5 mm from each
// inner wall → boss centres at x = ±32, y = ±17.
// BREP.cylinder(r, h) has its base at z=0 — translate to put base on floor (z=3).
const bossCenters = [
  [-32, -17], [32, -17], [-32, 17], [32, 17],
];
const bossPosts = bossCenters.map(([bx, by]) =>
  BREP.cylinder(2.5, 5).translate([bx, by, 3]),
);
// Bore: top of boss at z=8; bore from z=4 to z=8.1 (4.1 mm deep).
const bossBores = bossCenters.map(([bx, by]) =>
  BREP.cylinder(1, 4.1).translate([bx, by, 4]),
);

// --- Assemble ---
// 1. Carve the cavity, the lid lip step, and the vent slots out of the shell.
const shelled = BREP.cutAll([outer, cavity, lidLip, ...ventCutters]);

// 2. Fuse in the mounting posts (which rise from the cavity floor).
const withBosses = BREP.fuseAll([shelled, ...bossPosts]);

// 3. Drill the screw bores down through each boss.
return BREP.cutAll([withBosses, ...bossBores]);
